+/// Collect all column names referenced by an expression (recursive).
+/// Used to validate that expression-index terms only reference existing columns.
+fn collect_expr_column_refs<'a>(expr: &'a Expr, out: &mut Vec<&'a str>) {
+    match expr {
+        Expr::Column(col_ref, _) => out.push(col_ref.column.as_str()),
+        Expr::BinaryOp { left, right, .. } => {
+            collect_expr_column_refs(left, out);
+            collect_expr_column_refs(right, out);
+        }
+        Expr::UnaryOp { expr: inner, .. }
+        | Expr::IsNull { expr: inner, .. }
+        | Expr::Cast { expr: inner, .. }
+        | Expr::Collate { expr: inner, .. } => collect_expr_column_refs(inner, out),
+        Expr::Between {
+            expr: inner,
+            low,
+            high,
+            ..
+        } => {
+            collect_expr_column_refs(inner, out);
+            collect_expr_column_refs(low, out);
+            collect_expr_column_refs(high, out);
+        }
+        Expr::In {
+            expr: inner, set, ..
+        } => {
+            collect_expr_column_refs(inner, out);
+            if let InSet::List(items) = set {
+                for e in items {
+                    collect_expr_column_refs(e, out);
+                }
+            }
+        }
+        Expr::FunctionCall { args, .. } => {
+            if let FunctionArgs::List(items) = args {
+                for e in items {
+                    collect_expr_column_refs(e, out);
+                }
+            }
+        }
+        Expr::Case {
+            operand,
+            whens,
+            else_expr,
+            ..
+        } => {
+            if let Some(o) = operand {
+                collect_expr_column_refs(o, out);
+            }
+            for (cond, val) in whens {
+                collect_expr_column_refs(cond, out);
+                collect_expr_column_refs(val, out);
+            }
+            if let Some(el) = else_expr {
+                collect_expr_column_refs(el, out);
+            }
+        }
+        Expr::Like {
+            expr: operand,
+            pattern,
+            escape,
+            ..
+        } => {
+            collect_expr_column_refs(operand, out);
+            collect_expr_column_refs(pattern, out);
+            if let Some(esc) = escape {
+                collect_expr_column_refs(esc, out);
+            }
+        }
+        // Literals, placeholders, subqueries, etc. have no column refs.
+        _ => {}
+    }
